INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00304', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依土地稅法規定，下列關於地價稅之敘述何者錯誤？', '["地價稅之納稅義務人為土地所有權人", "土地所有權屬於公有或公同共有者，以管理機關或管理人為納稅義務人；土地所有權為分別共有 者，地價稅以共有人各按其應有部分為納稅義務人", "土地為信託財產者，於信託關係存續中，以受益人為地價稅之納稅義務人", "倘納稅義務人行蹤不明，主管稽徵機關得指定土地使用人負責代繳其使用部分之地價稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00305', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於土地增值稅，土地所有權移轉時申報移轉現值之審核標準，下列敘述何者錯誤？', '["申報人於訂定契約之日起30日內申報者，以訂約日當期之公告土地現值為準", "遺贈之土地，以遺贈人死亡日當期之公告土地現值為準", "申報人逾訂定契約之日起30日始申報者，以受理申報機關收件日當期之公告土地現值為準", "依法院判決移轉登記者，以法院判決作成日當期之公告土地現值為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00306', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於土地稅法之稽徵程序，下列敘述何者錯誤？', '["地價稅以每年7月31日為納稅義務基準日，由直轄市或縣（市）主管稽徵機關按照地政機關編送 之地價歸戶冊及地籍異動通知資料核定，於11月1日起1個月內一次徵收當年地價稅", "主管稽徵機關於查定納稅義務人每年應納地價稅額後，應填發地價稅稅單，分送納稅義務人或代繳 義務人，並將繳納期限、罰則、繳納方式、稅額計算方法等公告週知", "土地所有權移轉時，權利人及義務人應於訂定契約之日起30日內，檢附契約影本及有關文件，共 同向主管稽徵機關申報其土地移轉現值", "欠繳土地稅之土地，在欠稅未繳清前，不得辦理移轉登記或設定典權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00307', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於房屋稅，下列敘述何者錯誤？', '["房屋同時作住家及非住家用者，應以實際使用面積，分別按住家用或非住家用稅率，課徵房屋稅。 但非住家用者，課稅面積最低不得少於全部面積六分之一", "納稅義務人應於房屋建造完成之日起30日內檢附有關文件，向當地主管稽徵機關申報房屋稅籍有 關事項及使用情形；其有增建、改建、變更使用或移轉、承典時，亦同", "房屋遇有焚燬、坍塌、拆除至不堪居住程度者，應由納稅義務人申報當地主管稽徵機關查實後，在 未重建完成期內，停止課稅", "主管稽徵機關應依據不動產評價委員會評定之標準，核計房屋現值，並應通知納稅義務人。納稅義 務人如有異議，得於接到通知書之日起60日內，檢附證件，申請重行核計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00308', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於加值型及非加值型營業稅法「銷售貨物」及「視為銷售貨物」之規定，下列敘述何者錯誤？', '["將貨物之所有權移轉與他人，以取得代價者，為銷售貨物", "營業人銷售代銷貨物者，視為銷售貨物", "因信託行為成立，信託財產所有權自委託人移轉至受託人，視為銷售貨物", "營業人以其產製、進口、購買供銷售之貨物，轉供營業人自用，視為銷售貨物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00309', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，下列貨物或勞務何者應徵營業稅？', '["醫院提供之醫療勞務", "銷售稻米", "依法登記之報社銷售之廣告", "肩挑負販沿街叫賣者銷售之貨物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00310', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於加值型及非加值型營業稅法，下列敘述何者錯誤？', '["倘營業人於當期無銷售額，即不需向主管稽徵機關申報銷售額", "提供貨物與他人使用、收益，以取得代價者，為銷售勞務", "本法所稱保稅區營業人，包括政府核定之農業科技園區內之園區事業", "銷售與保稅區營業人供營運之貨物或勞務，營業稅稅率為零"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00311', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於菸酒稅法之規定，下列敘述何者錯誤？', '["菸酒稅於菸酒出廠或進口時徵收", "旅客自國外隨身攜帶之自用菸酒或調岸船員攜帶自用菸酒，未超過政府規定之限量者，免徵菸酒稅", "免稅菸酒因轉讓而不符免稅規定者，菸酒稅納稅義務人為轉讓之人或貨物持有人", "水果釀造酒之製造及販賣不屬於菸酒稅法規範範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00312', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於貨物稅條例，下列敘述何者錯誤？', '["產製貨物者，納稅義務人為產製廠商，於出廠時課徵貨物稅", "在廠內消費之應稅貨物，免徵貨物稅", "進口貨物者，納稅義務人為收貨人、提貨單或貨物持有人，於進口時課徵貨物稅", "委託代製貨物者，納稅義務人為受託之產製廠商，於出廠時課徵貨物稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00313', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '課徵稅捐應避免影響私經濟部門從事經濟活動之決策及資源配置，指下列何種租稅原則？', '["經濟發展", "租稅公平", "量能課稅", "租稅中立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
